<template>
  <section class="reading">
    <div class="container container_sec">
      <h2 class="reading__title">{{ oneBook }}</h2>
      <div style="color: black; font-weight: bold">{{ whatLang }}</div>
      <span v-for="(ve, idx) in zaToRead" :key="idx">
        <span class="supletter"
          ><sup :class="supClass">{{ ve[0] }}</sup></span
        >
        <span :class="zachClass">
          {{ ve[1] }}
        </span>
        &nbsp;
      </span>
    </div>

    <!-- <div class="container tooltip">
    {{ msg.za }}
    <span class="tooltiptext">{{ msg.te }}</span>
  </div> -->
  </section>
</template>

<script>
export default {
  name: 'TheReading',
  props: {
    msg: Object
  },
  data() {
    return {
      tooltip: ''
    }
  },
  computed: {
    // принимаем из App всю книгу, а не по отдельности части
    oneBook() {
      // console.log(this.msg.book.z[0])
      return (
        this.msg.book.boo + ' ' + this.msg.book.z[0] + ' ' + this.msg.book.z[1]
      )
    },
    whatLang() {
      return this.msg.l === true ? 'cs' : 'rus'
    },
    // вытаскиваем из названия книги и глав(стихов) целый текст для чтения
    zaToRead() {
      let s = this.f(
        this.msg.book.boo,
        this.msg.book.z[1] || this.msg.book.z[0],
        this.msg.l
      )
      return s
    },
    zachClass() {
      return this.msg.l ? 'csZach' : 'rusZach'
    },
    supClass() {
      return this.msg.l ? 'csSup' : 'rusSup'
    }
  },
  methods: {
    expandTire(pair) {
      // на вход типа 2-6
      let twoNums = pair.match(/\d{1,}/g)
      let delta = twoNums[1] - twoNums[0]
      let arra = []
      for (let i = 0; i <= delta; i++) {
        arra.push(i + +twoNums[0])
      }
      // выход 2, 3, 4, 5, 6
      return arra.join(', ')
    },
    feedGlava(lastVerse, lenGlava, p) {
      // вернуть кусок стихов для дополнения главы
      let addArr = []
      for (let m = p; m <= lenGlava - lastVerse; m++) {
        let k = lastVerse + m
        addArr.push(k.toString())
      }
      return addArr
    },
    f(a, b, la) {
      let lang = la ? 'cs' : 'rus'
      // console.log(lang)
      // переопределяем а, как книгу, наденную в базе книг
      this.$store.state.arrBook.forEach((book) => {
        // есть ли книга в переданной строке
        if (a.includes(book)) {
          a = book
        }
      })
      // b = 'XIV, 19–20, 23 – XV, 7.'
      // XXII, 39–42, 45 – XXIII, 1.
      // нужно "растянуть" тире
      // let bb = b
      // пары чисел, разделенные тире, заменяем на последовательности
      let reTire = /\d{1,}–\d{1,}/
      if (b === 'XIII, 31 –XVIII, 1.') {
        b = 'XIII, 31–38; XIV, 1–31; XV, 1–27; XVI, 1–33; XVII, 1–26; XVIII, 1.'
      }

      let y = [...b.matchAll(new RegExp(reTire, 'g'))]
      let newbb = ''
      // если тире есть
      if (y.length) {
        y.forEach((ma) => {
          let expand = this.expandTire(ma[0])
          newbb = b.replace(ma[0], expand)
          b = newbb
        })
      } else {
        // если тире в парах числах нет
        newbb = b
      }
      // самый последний стих (его номер) в текущем зачале, сравняли с нижеслед. i

      // console.log(newbb)
      let ast = +newbb.match(/\d{1,}(?!$)(?=\.$)/gm)[0] - 1

      // главы, содержащие дефис; разделенные точкой с запятой; или просто одиночные главы
      let reSemi = /[A-Z]{1,}.+\d\s–|[A-Z]{1,}.+?\d?;|[A-Z]{1,}.+\d/g
      // console.log(newbb.match(reSemi))
      // let arrayVerse = []
      let zachalo = []
      // console.log(newbb.match(reSemi))
      let ww = 0
      let wZ = 0 // учет уже найденного номера зачала, как в одной и той же главе, так и в двух, которые через тире
      let mZachL = false // зачало, у которого *0 стоит в середине, вырезать до нуля
      let mZachR = false // зачало, у которого *0 стоит в середине, вырезать после нуля
      newbb.match(reSemi).forEach((el) => {
        // составлять строку текста

        let xx = el.match(/[A-Z]{1,}/g) // всегда одна глава в массиве
        // console.log(el)
        let nums = el.match(/\d{1,}(?!_)/g) // массив стихов (если между главами минус, то первый элемент нужно дополнить влево до 0)
        let glava = this.$store.state[a][xx[0]][lang]
        if (el.includes('–')) {
          ww = 1
          let dopGlava = this.feedGlava(+nums[nums.length - 1], glava.length, 1)
          nums.push(...dopGlava)
        } else if (ww === 1) {
          let dopGlava = this.feedGlava(1, +nums[0] - 1, 0)
          // теперь, когда первая глава просмотрена, вторую главу дополняем сначала
          nums.splice(0, 0, ...dopGlava)
        }
        // console.log(nums)
        // теперь перебираем главы и собираем массив с номерами и стихами
        glava.forEach((verse, i) => {
          if (nums.includes((i + 1).toString())) {
            // нужно, чтобы стих имел ТОЛЬКО один паттерн со звездочкой
            // if (verse.includes('*0')) console.log(verse)
            // arrayVerse.push(verse)
            if (!la) {
              zachalo.push([i + 1, verse])
            } else {
              // массив символов со звездочками (включая *0) длиной от 1 до 2 либо null
              // если wZ=0, то risk всегда есть для первого стиха, для стихов без звездочек он равен null
              let risk = verse.match(
                /\*\d{1,}[p]|\*\d{1,}[x]|\*\d{1,}[y]|\*\d{1,}/gm
              )
              if (!risk) {
                zachalo.push([i + 1, verse])
                return
              }
              // зачало, у которого в среднем стихе есть *0, как граница резки, последующие x и y игнорируем (wZ=0)
              if (risk && risk[0].includes('x') && wZ === 0) {
                mZachL = true
              }
              if (risk && risk[0].includes('y') && wZ === 0) {
                mZachR = true
              }
              let r =
                /.*\*\d{1,}[p]|.*\*\d{1,}[x]|.*\*\d{1,}[y]|.*\*[^0]\d{0,}/g // часть строки для замены, не захватывая *0
              // заменить букву р на цифру 9 (Кор. 182p зачало)
              // let dopStar = verse.match(
              //   /.*\*\d{1,}[p]|.*\*\d{1,}[x]|.*\*\d{1,}/gm
              // )
              //let zachNo = -1
              let zach = ''
              // не бывает, чтобы wZ = 0 и risk.length = 1 и risk[0] = '*0'
              if (wZ === 0 && risk.length === 1 && risk[0] !== '*0') {
                wZ = 1 // первое зачало учли
                zach = this.$store.state.zaNo[a][risk[0]][1]
                // let pie = verse.slice(
                //   0,
                //   verse.indexOf(risk[0]) + risk[0].length
                // )
                verse = verse.replace(r, zach)
              } else if (wZ === 0 && risk.length === 2 && risk[0] !== '*0') {
                wZ = 1 // первое зачало учли
                zach = this.$store.state.zaNo[a][risk[0]][1]
                verse = verse.replace(r, zach)
                // должна быть замена *0 - в самом низу
              } else if (wZ === 0 && risk.length === 2 && risk[0] === '*0') {
                wZ = 1 // первое зачало учли
                zach = this.$store.state.zaNo[a][risk[1]][1]
                verse = verse.replace(r, zach)
                // теперь работаем, когда первое зачало уже прошло
              } else if (risk && wZ === 1) {
                // ниже только один случай, когда зачало[0] содержит в себе 'x'
                if (
                  risk.length === 1 &&
                  risk[0] === '*0' &&
                  mZachL &&
                  i !== 29
                ) {
                  verse = verse.slice(0, verse.indexOf('*0'))
                  // console.log(mZachL)
                  // в самом низу заменяем *0 на пустоту
                } // ниже Мк. 20 зач., V, 35, обрезка слева; i === 29 для Ин. 60 зач.
                else if (
                  risk.length === 1 &&
                  risk[0] === '*0' &&
                  (mZachR || i === 29)
                ) {
                  verse = verse.replace(/.*\*\d{1,}\s/gm, '')
                  // console.log('mZachR')
                } else if (risk.length === 1 && risk[0] === '*0' && ast === i) {
                  verse = verse.slice(0, verse.indexOf('*0')) // подрезаем
                  // console.log('последний стих') // Евр. 330
                  // в самом низу заменяем *0 на пустоту
                }
                // если risk содержит *0 первым перед *65, то вырезаем до него
                else if (risk.length === 2 && risk[0] === '*0') {
                  verse = verse.slice(0, verse.indexOf('*0')) // подрезаем стих по *0
                  // в самом низу заменяем *0 на пустоту
                } else if (risk.length === 2 && risk[1] === '*0') {
                  verse = verse.replace(risk[0], '') // сначала заменяем первый эл-т типа *65 на пусто
                  let beforeZero = verse.slice(0, verse.indexOf('*0'))
                  verse = beforeZero
                }
              }
              // окончально зачищаем, даже если в середине отрывка
              // нужно добавить условие, что это точно конечный стих
              let comma = /,|:/gm
              if (verse[verse.length - 1].match(comma) && ast === i) {
                let v1 = verse.replace(/.$/, '.')
                verse = v1
              }
              let end = /\*\d{1,}[p]|\*\d{1,}[x]|\*\d{1,}/gm
              verse = verse.replace(end, '')

              zachalo.push([i + 1, verse])
            }
          }
        })
      })
      // 5-ый случай: I, 1–2, 10–12; II, 6–10.
      // 6-ой случай: XV, 22, 25, 33–41.
      // 7-ой случай: XXI, 8–9, 25–27, 33–36.
      // 8-ой случай: XXII, 39–42, 45 – XXIII, 1.
      // 9-ый случай: I, 39–49, 56.
      return zachalo
    }
  }
}
</script>

