  }
  .csZach {
    font-family: 'Hirmos Ucs', sans-serif;
    font-size: 2.2rem;
  }
}

@media screen and (min-width: 991px) {
}

// как только мы достигаем min 1200px (увеличивая экран) и больше
@media screen and (min-width: 1200px) {
}

