<script>
export default {
  name: 'TheInfo',
  props: {
    msg: String
  },
  data() {
    return {
      s: null,
      clk: false
    }
  },
  methods: {
    toPlay(m) {
      if (this.s === null && !this.clk) {
        this.clk = true
        this.s = new Audio(require(`@/assets/audio/${m}.ogg`))
        this.s.play()
      } else if (this.clk && this.s !== null) {
        this.clk = false
        this.s.pause()
        this.s = null
      }
    }
  }
}
</script>

