<template>
  <section class="graph">
    <div class="container container_sec">
      <div class="graph-field">
        <h2>{{ msg }}</h2>
        <div style="margin: 0 auto">
          <Bar
            :chart-options="chartOptions"
            :chart-data="chartData"
            :chart-id="chartId"
            :dataset-id-key="datasetIdKey"
            :plugins="plugins"
            :css-classes="cssClasses"
            :styles="styles"
            :width="width"
            :height="height"
          >
          </Bar>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
import { Bar } from 'vue-chartjs'
import {
  Chart as ChartJS,
  Title,
  Tooltip,
  // Legend,
  BarElement,
  CategoryScale,
  LinearScale
} from 'chart.js'
import ChartJsPluginDataLabels from 'chartjs-plugin-datalabels'
ChartJS.register(
  Title,
  Tooltip,
  BarElement,
  CategoryScale,
  LinearScale,
  ChartJsPluginDataLabels
)
export default {
  name: 'TheGraph',
  components: {
    Bar
  },
  props: {
    msg: String,
    chartId: {
      type: String,
      default: 'bar-chart'
    },
    datasetIdKey: {
      type: String,
      default: 'label'
    },
    width: {
      type: Number,
      default: 400
    },
    height: {
      type: Number,
      default: 400
    },
    cssClasses: {
      default: '',
      type: String
    },
    styles: {
      type: Object,
      default: () => {}
    },
    plugins: {
      type: Object,
      default: () => {}
    }
  },
  data() {
    return {
      chartData: {
        labels: ['от Матфея', 'от Марка', 'от Луки', 'от Иоанна', 'Апостол'],
        datasets: [
          {
            label: 'Всего',
            borderColor: 'black',
            borderWidth: 1,
            borderRadius: 4,
            backgroundColor: [
              'rgba(255, 99, 132, 0.2',
              'rgba(54, 162, 235, 0.2',
              'rgba(255, 206, 86, 0.2)',
              'rgba(75, 192, 192, 0.2)',
              'rgba(153, 102, 255, 0.2)'
            ],
            data: [this.getZ(), 71, 114, 67, 335],
            datalabels: {
              color: 'black',
              anchor: 'end',
              align: 'top'
              // offset: 6
            }
          }
        ]
      },
      chartOptions: {
        scales: {
          y: {
            max: 400,
            ticks: { color: '#0000cd', beginAtZero: true }
          },
          x: {
            ticks: { color: '#0000cd', beginAtZero: true }
          }
        },
        plugins: {
          // title: {
          //   display: true,
          //   text: this.msg
          // }
        },
        responsive: true
      }
    }
  },
  methods: {
    getZ() {
      return 116
    }
  }
}
</script>

