import ToggleBtn from './components/ui/ToggleBtn.vue'
import TheShedule from './components/TheShedule.vue'
import TheGraph from './components/TheGraph.vue'
import TheReading from './components/TheReading.vue'
import TheInfo from './components/TheInfo.vue'

