      isTodayNum: true,
      mIndex: null,
      dateValue: 0,
      month: '',
      currDay: 0,
      day: 0,
      weekDay: '',
      dataToParse: '',
      lang: true,
      reading:
        '1_Тим., 278 зач., I, 1–7. Лк., 86 зач., XVII, 20–25. Апп.: Флм., последи́ 302 зач., I, 1–25. Лк., 50 зач., X, 1–15.',
      // reading: '2_Сол., 276 зач., II, 13 – III, 5. Лк., 80 зач., XVI, 1–9.',
      zRu: null,
      zCs: null,
      service1: '',
      service2: '',
      isLitera: '',
      parse: [
        {
          Утреня: [{ boo: 'Лк.', z: ['24 зач.', 'VI, 17–23.'] }]
        },
        {
          ['Литургия']: [
            { boo: 'Деян.', z: ['24 зач.', 'X, 1–16.'] },
            { boo: 'Ин.', z: ['24 зач.', 'VI, 56–69.'] },
            { boo: 'Прп.: Евр.', z: ['334 зач.', 'XIII, 7–16.'] },
            { boo: 'Мф.', z: ['43 зач.', 'XI, 27–30.'] }
          ]
        }
      ]
    }
  },
  mixins: [update],
  created() {
