    window.addEventListener('resize', this.checkScreen)
    this.checkScreen()
    //this.$store.getters['mfBook']
    // let m = 1
    // let timerId = setInterval(() => {
    //   console.log(m)
    //   this.receiveDate(0, m)
    //   m++
    // }, 2000)
    // setTimeout(() => {
