  },
  methods: {
    checkScreen() {
      this.windowWidth = window.innerWidth
      if (this.windowWidth <= 750) {
        this.isMobile = true
      } else this.isMobile = false
    },
    goTo() {
      this.toggleSide = !this.toggleSide
    },
    toggleLang(isActive) {
      this.lang = isActive
    },
    // передаем всю книгу, а не по-отдельности части
    toRead(b) {
      this.isTodayNum = false
      this.selectedComponent = 'the-reading'
      // z = 'Hover (Tooltip text) over me'
      // let t = ''
      // if (z.includes('(')) {
      //   t = z.slice(z.indexOf('(') + 1, 19)
      //   z = 'Hover over me'
      // }
      // передаем целую книгу
      this.currentReading = { book: b, l: this.lang }
    },
    setSelectedComponent(comp, p) {
      // если мобильная, то выключаем боковое меню
      if (this.isMobile && (p === 2 || p === 1)) {
        this.toggleSide = !this.toggleSide
      }
      if (comp === 'the-shedule') this.isTodayNum = true
      this.selectedComponent = comp
      // this.currentReading = toRead
    },
    receiveDate(diff) {
      let now = new Date()
      // let now = new Date(2022, 3, 22)

      this.currDay = now.getDate()

      if (diff === 1) {
        this.dateValue++
        now.setDate(now.getDate() + this.dateValue)
      } else if (diff === -1) {
        this.dateValue--
        now.setDate(now.getDate() + this.dateValue)
      } else {
        this.dateValue = 0
      }

      this.mIndex = now.getMonth()
      const nameOfMonth = [
        'января',
        'февраля',
        'марта',
        'апреля',
        'мая',
        'июня',
        'июля',
        'августа',
        'сентября',
        'октября',
        'ноября',
        'декабря'
      ]
      const days = ['вс.', 'пн.', 'вт.', 'ср.', 'чт.', 'пт.', 'сб.']
      this.month = nameOfMonth[this.mIndex]
      this.day = now.getDate()
      this.weekDay = days[now.getDay()]
      this.showParse()
    },
    showParse() {
      this.dataToParse =
        this.$store.state.calendar[this.mIndex][this.mIndex][this.day - 1]
      // this.dataToParse = 'можно подставить строку из календаря любую'
      this.reading = this.dataToParse // исправить, если будет компонента
      if (this.mIndex === 3 && this.day === 22) {
        this.parse = this.$store.state.vp
        this.isLitera = ''
      } else this.parse = this.pickupParse(this.dataToParse)
    },
    pickupParse(str) {
      // let a = []
      let kl = str[str.length - 1]
      if (kl === 'Е') {
        this.isLitera = ''
      } else if (kl === 'П') {
        this.isLitera = 'Литургия Преждеосвященных Даров'
      } else if (kl === 'В') {
        this.isLitera = 'Литургия свт. Василия Великого'
      } else if (kl === 'Н') {
        this.isLitera = 'Литургии не положено'
      } else {
        this.isLitera = 'Литургия свт. Иоанна Златоустаго'
      }
      // let third = str.indexOf('На 3-м часе')
      // let nine = str.indexOf('На 9-м часе')
      // let six = str.indexOf('На 6-м часе')
      // let vecher = str.indexOf('На веч.')
      // let y = str.indexOf('Утр.')
      // let l = str.indexOf('Лит.')

      // учесть пустой символ в конце каждой службы
      let array = [
        ['На 9-м часе:', 'На 9-м часе'],
        ['На веч.:', 'На вечерне'],
        ['Утр. –', 'Утреня'],
        ['На 1-м часе:', 'На 1-м часе'],
        ['На 3-м часе:', 'На 3-м часе'],
        ['На 6-м часе:', 'На 6-м часе'],
        ['Лит. –', 'Литургия']
      ]
      let actualServ = []
      array.forEach((el) => {
        let matchAl = [...str.matchAll(new RegExp(el[0], 'g'))]
        if (matchAl.length) {
          // сразу заменили на полное название службы
          matchAl[0][0] = el[1]
          // записываем (вместо) длину аббр. службы, кот. будет use
          matchAl[0]['groups'] = el[0].length
          actualServ.push(matchAl[0])
        }
      })
      // если не обнаружены упоминаня служб
      // отправляем все в Литургию
      let serv = []
      if (!actualServ.length) {
        let tempLiturg = {}
        tempLiturg[''] = this.filterBook(str)
        serv.push(tempLiturg)
        return serv
      }
      // форматируем к виду { 0: ['Утр. -', idx, length], 1: ['Лит. -', idx, length]}
      let sortServ = actualServ.sort((prev, next) => prev.index - next.index)
      // console.log(sortServ)
      serv = sortServ.reduce((acc, service, ix) => {
        // стартовый индекс вырезки, база - первая буква аббр. службы в исх. строке
        // позиция аббр. + его длина + один пробел
        let startIx = service.index + sortServ[ix]['groups'] + 1
        // конечный индекс вырезки, как начало следующего куска минус 1
        let endIx = 0
        if (sortServ[ix + 1]) {
          endIx = sortServ[ix + 1].index - 1
        } else {
          endIx = str.length
        }
        let pie = str.slice(startIx, endIx)
        let obj = {}
        obj[service[0]] = this.filterBook(pie)
        acc.push(obj)
        return acc
      }, [])
      // console.log(serv)

      // let utren = ''
      // let tempUtr = {}
      // let liturg = ''
      // let tempLiturg = {}
      // // если есть 9 час, значит есть и Литургия и все др. часы (таких всего два случая)
      // if (nine > -1) {
      //   let tempFirst = {}
      //   let tempThird = {}
      //   let tempNinth = {}
      //   tempFirst['На 1-м часе'] = this.filterBook(str.slice(13, third - 1))
      //   a.push(tempFirst)
      //   tempThird['На 3-м часе'] = this.filterBook(
      //     str.slice(third + 13, six - 1)
      //   )
      //   a.push(tempThird)
      //   tempUtr['На 6-м часе'] = this.filterBook(str.slice(six + 13, nine - 1))
      //   a.push(tempUtr)
      //   tempNinth['На 9-м часе'] = this.filterBook(str.slice(nine + 13, l - 1))
      //   a.push(tempNinth)
      //   tempLiturg['Литургия'] = this.filterBook(str.slice(l + 7, str.length))
      //   a.push(tempLiturg)
      // } else if (y === -1 && six > -1 && vecher > -1) {
      //   utren = str.slice(13, vecher - 1)
      //   tempUtr['На 6-м часе'] = this.filterBook(utren)
      //   a.push(tempUtr)
      //   liturg = str.slice(vecher + 9, str.length)
      //   tempLiturg['На вечерне'] = this.filterBook(liturg)
      //   a.push(tempLiturg)
      // } else if (y > -1 && l > -1 && vecher === -1) {
      //   // вырезаем часть всей строки с утреней без 'Утр.'
      //   utren = str.slice(7, l - 1)
      //   tempUtr['Утреня'] = this.filterBook(utren)
      //   a.push(tempUtr)
      //   // вырезаем часть всей строки с литургией без 'Лит.'
      //   liturg = str.slice(l + 7, str.length)
      //   tempLiturg['Литургия'] = this.filterBook(liturg)
      //   a.push(tempLiturg)
      // } else if (y > -1 && l > -1 && vecher > -1) {
      //   console.log('и Утреня, и 6-час, и веч., и Литургия')
      // } else {
      //   // если Утр. отсутствует в строке, то отправляем все в Литургию
      //   tempLiturg[''] = this.filterBook(str)
      //   a.push(tempLiturg)
      // }
      return serv
    },
    filterBook(strOfService) {
      let arrBook = this.$store.state.arrBook
      let books = []
      let startIndex = 0 // начальный индекс для куска, содержащего в конце ':'
      let arrBooks = []
      arrBook.forEach((b) => {
        let matchAl = [...strOfService.matchAll(new RegExp(b, 'g'))]
        if (matchAl.length) {
          //console.log(matchAl)
          // собираем все книги в один сложный массив, в том числе, если есть дубликаты книг
          arrBooks.push(matchAl)
        }
      })
      // console.log(arrBooks)
      // собрали массив с книгами и их индексами
      books = arrBooks
        .reduce((acc, m) => {
          let obj = {}
          m.forEach((elem) => {
            obj['boo'] = elem[0]
            obj['idx'] = elem.index
            acc.push(obj)
            obj = {}
          })
          return acc
        }, [])
        .sort((prev, next) => prev.idx - next.idx)
      // console.log(books)
      // улавливаем зачала и стихи, если зачал нет, то пустой массив
      let zs = strOfService.match(
        /\d{1,}( зач\. \(от полу́\),)|\d{1,}( зач\.,)|\d{1,}( зач\. \(первое\),)|\d{1,}( зач\. \(второе\),)/g
      ) || ['']

      // let ch = strOfService.match(
      //   /[A-Z]{1,},\s(\d{1,}–\d{1,})|[A-Z]{1,},\s\d{1,}(.|\s)–(.|\s)[A-Z]{1,},\s\d{1,}/gm
      // )
      let ch = strOfService.match(/[A-Z]{1,}.*?\./gm)
      // console.log(ch)
      // добавляем добавки
      books.map((b, i, books) => {
        let bb = b['boo'] // сохраняем значение старого ключа
        // кусок, в котором содержится ' : '
        let piece = ''
        // кусочек, который может быть добавлен к значению старого ключа
        let additionalPiece = ''
        piece = strOfService.slice(startIndex, b.idx)
        if (piece.includes(':') || strOfService.includes('Ев. сост')) {
          // находим блок в piece, который заканчивается цифрой
          let part = piece.match(/.*(\d)/gm) || ['0']
          // находим позицию последней цифры
          let posLastDigit = part[0].length
          // вырезаем часть, которую нужно приставить к bb (начиная с + 2, т. к. до нее м. б. ". " или ", ")
          // если цифры нет, то значит добавка находится в самом начале
          if (part[0].length > 1) {
            additionalPiece = piece.slice(posLastDigit + 2, piece.length)
          } else additionalPiece = piece
        } else if (strOfService.includes('Ев. ')) {
          additionalPiece = strOfService.match(
            /(Ев\.)(\s|.)\d{1,}(-е,(\s|.))/gm
          )[0]
        }
        // console.log(bb)

        b['boo'] = additionalPiece + bb
        if (zs.length) {
          b['z'] = [zs[i], ch[i]]
        } else {
          b['z'] = [ch[i]]
        }

        startIndex = books[i].idx
        delete b['idx']
      })
      // console.log(books)
      return books
    }
  },
  computed: {
    addAct() {
      return this.toggleSide ? 'active' : ''
    },
    currentProps() {
      let propers = null
      if (this.selectedComponent === 'the-graph') {
        propers = 'Количество зачал в Книгах'
      } else if (this.selectedComponent === 'the-info') {
        propers = 'Справка'
      } else if (this.selectedComponent === 'the-reading') {
        // уже кликнули на зачало и передаем всю книгу
        propers = this.currentReading
      } else if (this.selectedComponent === 'the-shedule') {
        propers = { isLitera: this.isLitera, parse: this.parse }
      }
      return { msg: propers }
    }
  },
  watch: {
    lang() {
      if (this.currentReading) {
        this.currentReading.l = this.lang
      }
    }
  }
}
</script>

